215	          label: b.label,
216	          amount: b.amount,
217	          reason: `${ctx.tickets} of ${ctx.capacity} sold`,
218	        });
219	      } else {
220	        notTriggered.push({
221	          label: b.label,
222	          amount: b.amount,
223	          reason:
224	            ctx.capacity != null
